    "params": {
      "audio_id": "{{audio_id}}"
    },
    "audio_id": "{{audio_id}}",
    "screen": "child_audio_player"
  }
}

{
  "target": {
    "type": "custom",
    "user_ids": [
      "{{parent_user_id}}",
      "{{parent_user_id_2}}"
    ],
    "child_ids": [
      "{{child_id}}",
      "{{child_id_2}}"
    ]
  },
  "notification": {
    "title": "New story is ready",
    "body": "Tap to read it now.",
    "event_type": "manual_story_update",
    "route": "story_detail",
    "fallback_route": "parent_dashboard",
    "params": {
      "story_id": "{{story_id}}"
    },
    "data": {
      "source": "admin_ui"
    }
  },
  "delivery": {
    "channel_id": "story-updates",
    "priority": "high",
    "sound": "default"
  }
}

{
  "target": {
    "type": "parents"
  },
  "notification": {
